import{_ as a,c as e,o,a1 as r}from"./chunks/framework.DILC4Csi.js";const b=JSON.parse('{"title":"Bear 集成: 自动保存计划 | Plannotator","description":"学习 Plannotator 的 Bear 集成配置方法。通过 x-callback-url 自动保存批准的计划，智能生成标签，实现知识沉淀和计划归档。","frontmatter":{"title":"Bear 集成: 自动保存计划 | Plannotator","sidebarTitle":"计划自动存到 Bear","subtitle":"Bear 集成: 自动保存批准的计划 | Plannotator","description":"学习 Plannotator 的 Bear 集成配置方法。通过 x-callback-url 自动保存批准的计划，智能生成标签，实现知识沉淀和计划归档。","tags":["集成","Bear","笔记应用","知识沉淀"],"prerequisite":["installation-claude-code","platforms-plan-review-basics"],"order":3},"headers":[],"relativePath":"zh/backnotprop/plannotator/advanced/bear-integration/index.md","filePath":"zh/backnotprop/plannotator/advanced/bear-integration/index.md"}'),l={name:"zh/backnotprop/plannotator/advanced/bear-integration/index.md"};function i(n,t,d,s,c,p){return o(),e("div",null,[...t[0]||(t[0]=[r(`<h1 id="bear-集成-自动保存批准的计划" tabindex="-1">Bear 集成：自动保存批准的计划 <a class="header-anchor" href="#bear-集成-自动保存批准的计划" aria-label="Permalink to &quot;Bear 集成：自动保存批准的计划&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><p>启用 Bear 集成后，每次批准计划时，Plannotator 会自动将计划保存到你的 Bear 笔记中，包括：</p><ul><li>自动生成的标题（从计划提取）</li><li>智能标签（项目名、关键词、编程语言）</li><li>完整的计划内容</li></ul><p>这样你就能在一个地方管理所有批准的计划，方便后续查阅和知识沉淀。</p><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><p>你可能遇到过这些情况：</p><ul><li>AI 生成的计划很好，但想保存下来以后参考</li><li>在 Bear 里手动复制粘贴计划太麻烦</li><li>不同项目的计划混在一起，没有标签管理</li></ul><p>有了 Bear 集成，这些问题都能自动解决。</p><h2 id="什么时候用这一招" tabindex="-1">什么时候用这一招 <a class="header-anchor" href="#什么时候用这一招" aria-label="Permalink to &quot;什么时候用这一招&quot;">​</a></h2><ul><li>你使用 Bear 做主要笔记应用</li><li>需要归档批准的计划做知识库</li><li>希望通过标签快速检索历史计划</li></ul><div class="info custom-block"><p class="custom-block-title">关于 Bear</p><p>Bear 是一款 macOS 上的 Markdown 笔记应用，支持标签、加密、同步等功能。如果你还没安装，可以访问 <a href="https://bear.app/" target="_blank" rel="noreferrer">bear.app</a> 了解。</p></div><h2 id="🎒-开始前的准备" tabindex="-1">🎒 开始前的准备 <a class="header-anchor" href="#🎒-开始前的准备" aria-label="Permalink to &quot;🎒 开始前的准备&quot;">​</a></h2><ul><li>已安装 Plannotator（参见<a href="./../../start/installation-claude-code/">安装教程</a>）</li><li>已安装 Bear 并能够正常使用</li><li>了解基本的计划评审流程（参见<a href="./../../platforms/plan-review-basics/">计划评审基础</a>）</li></ul><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>Bear 集成的核心是 <strong>x-callback-url</strong> 协议：</p><ol><li>在 Plannotator UI 中启用 Bear 集成（存储在浏览器 localStorage）</li><li>批准计划时，Plannotator 发送 <code>bear://x-callback-url/create</code> URL</li><li>系统使用 <code>open</code> 命令自动打开 Bear 创建笔记</li><li>计划内容、标题、标签自动填入</li></ol><p><strong>关键特点</strong>：</p><ul><li>无需配置 vault 路径（不像 Obsidian 需要指定 vault）</li><li>标签智能生成（最多 7 个）</li><li>批准计划时自动保存</li></ul><div class="tip custom-block"><p class="custom-block-title">与 Obsidian 的区别</p><p>Bear 集成更简单，不需要配置 vault 路径，只需一个开关。但 Obsidian 可以指定保存文件夹和更多定制化。</p></div><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-打开-plannotator-设置" tabindex="-1">第 1 步：打开 Plannotator 设置 <a class="header-anchor" href="#第-1-步-打开-plannotator-设置" aria-label="Permalink to &quot;第 1 步：打开 Plannotator 设置&quot;">​</a></h3><p>当 AI Agent 生成计划并打开 Plannotator UI 后，点击右上角的 ⚙️ <strong>Settings</strong> 按钮。</p><p><strong>你应该看到</strong>：设置面板弹出，包含多个配置选项</p><h3 id="第-2-步-启用-bear-集成" tabindex="-1">第 2 步：启用 Bear 集成 <a class="header-anchor" href="#第-2-步-启用-bear-集成" aria-label="Permalink to &quot;第 2 步：启用 Bear 集成&quot;">​</a></h3><p>在设置面板中找到 <strong>Bear Notes</strong> 部分，点击开关按钮。</p><p><strong>为什么</strong> 开关会从灰色（禁用）变为蓝色（启用），同时存储到浏览器的 localStorage 中。</p><p><strong>你应该看到</strong>：</p><ul><li>Bear Notes 开关变蓝</li><li>描述文字：&quot;Auto-save approved plans to Bear&quot;</li></ul><h3 id="第-3-步-批准计划" tabindex="-1">第 3 步：批准计划 <a class="header-anchor" href="#第-3-步-批准计划" aria-label="Permalink to &quot;第 3 步：批准计划&quot;">​</a></h3><p>完成计划评审后，点击底部的 <strong>Approve</strong> 按钮。</p><p><strong>为什么</strong> Plannotator 会读取 Bear 设置，如果已启用，会在批准的同时调用 Bear 的 x-callback-url。</p><p><strong>你应该看到</strong>：</p><ul><li>Bear 应用自动打开</li><li>新建笔记窗口弹出</li><li>标题和内容已自动填充</li><li>标签已自动生成（以 <code>#</code> 开头）</li></ul><h3 id="第-4-步-查看保存的笔记" tabindex="-1">第 4 步：查看保存的笔记 <a class="header-anchor" href="#第-4-步-查看保存的笔记" aria-label="Permalink to &quot;第 4 步：查看保存的笔记&quot;">​</a></h3><p>在 Bear 中，检查新建的笔记，确认：</p><ul><li>标题是否正确（来自计划的 H1）</li><li>内容是否完整（包含计划全文）</li><li>标签是否合理（项目名、关键词、编程语言）</li></ul><p><strong>你应该看到</strong>： 类似这样的笔记结构：</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## User Authentication</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#032F62;--shiki-light-text-decoration:underline;--shiki-dark:#DBEDFF;--shiki-dark-text-decoration:underline;">完整的计划内容...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">#plannotator #myproject #authentication #typescript #api</span></span></code></pre></div><h2 id="检查点-✅" tabindex="-1">检查点 ✅ <a class="header-anchor" href="#检查点-✅" aria-label="Permalink to &quot;检查点 ✅&quot;">​</a></h2><ul><li>[ ] Settings 中 Bear Notes 开关已启用</li><li>[ ] 批准计划后 Bear 自动打开</li><li>[ ] 笔记标题与计划的 H1 一致</li><li>[ ] 笔记包含完整的计划内容</li><li>[ ] 标签包含 <code>#plannotator</code> 和项目名</li></ul><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="bear-没有自动打开" tabindex="-1">Bear 没有自动打开 <a class="header-anchor" href="#bear-没有自动打开" aria-label="Permalink to &quot;Bear 没有自动打开&quot;">​</a></h3><p><strong>原因</strong>：系统 <code>open</code> 命令失败，可能是：</p><ul><li>Bear 未安装或未从 App Store 下载</li><li>Bear 的 URL scheme 被其他应用劫持</li></ul><p><strong>解决方法</strong>：</p><ol><li>确认 Bear 已正常安装</li><li>在终端中手动测试：<code>open &quot;bear://x-callback-url/create?title=test&quot;</code></li></ol><h3 id="标签不符合预期" tabindex="-1">标签不符合预期 <a class="header-anchor" href="#标签不符合预期" aria-label="Permalink to &quot;标签不符合预期&quot;">​</a></h3><p><strong>原因</strong>：标签是自动生成的，规则如下：</p><ul><li>必选：<code>#plannotator</code></li><li>必选：项目名（从 git 仓库名或目录名提取）</li><li>可选：从 H1 标题提取最多 3 个关键词（排除停用词）</li><li>可选：从代码块提取编程语言标签（排除 json/yaml/markdown）</li><li>最多 7 个标签</li></ul><p><strong>解决方法</strong>：</p><ul><li>标签不符合预期时，可以在 Bear 中手动编辑</li><li>如果项目名不对，检查 git 仓库配置或目录名</li></ul><h3 id="批准但没有保存" tabindex="-1">批准但没有保存 <a class="header-anchor" href="#批准但没有保存" aria-label="Permalink to &quot;批准但没有保存&quot;">​</a></h3><p><strong>原因</strong>：</p><ul><li>Bear 开关未启用（检查 Settings）</li><li>网络错误或 Bear 响应超时</li><li>计划内容为空</li></ul><p><strong>解决方法</strong>：</p><ol><li>确认 Settings 中开关是蓝色（启用状态）</li><li>查看终端是否有错误日志（<code>[Bear] Save failed:</code>）</li><li>重新批准计划</li></ol><h2 id="标签生成机制详解" tabindex="-1">标签生成机制详解 <a class="header-anchor" href="#标签生成机制详解" aria-label="Permalink to &quot;标签生成机制详解&quot;">​</a></h2><p>Plannotator 会智能生成标签，让你在 Bear 中快速检索计划。以下是标签的生成规则：</p><table tabindex="0"><thead><tr><th>标签来源</th><th>示例</th><th>优先级</th></tr></thead><tbody><tr><td>固定标签</td><td><code>#plannotator</code></td><td>必选</td></tr><tr><td>项目名称</td><td><code>#myproject</code>、<code>#plannotator</code></td><td>必选</td></tr><tr><td>H1 关键词</td><td><code>#authentication</code>、<code>#api</code></td><td>可选（最多 3 个）</td></tr><tr><td>编程语言</td><td><code>#typescript</code>、<code>#python</code></td><td>可选</td></tr></tbody></table><p><strong>停用词列表</strong>（不会作为标签）：</p><ul><li><code>the</code>, <code>and</code>, <code>for</code>, <code>with</code>, <code>this</code>, <code>that</code>, <code>from</code>, <code>into</code></li><li><code>plan</code>, <code>implementation</code>, <code>overview</code>, <code>phase</code>, <code>step</code>, <code>steps</code></li></ul><p><strong>编程语言排除</strong>（不会作为标签）：</p><ul><li><code>json</code>, <code>yaml</code>, <code>yml</code>, <code>text</code>, <code>txt</code>, <code>markdown</code>, <code>md</code></li></ul><details class="details custom-block"><summary>示例：标签生成过程</summary><p>假设计划标题为 &quot;Implementation Plan: User Authentication System in TypeScript&quot;，代码块包含 Python 和 JSON：</p><ol><li><strong>固定标签</strong>：<code>#plannotator</code></li><li><strong>项目名</strong>：<code>#myproject</code>（假设 git 仓库名）</li><li><strong>H1 关键词</strong>： <ul><li><code>implementation</code> → 排除（停用词）</li><li><code>plan</code> → 排除（停用词）</li><li><code>user</code> → 保留 → <code>#user</code></li><li><code>authentication</code> → 保留 → <code>#authentication</code></li><li><code>system</code> → 保留 → <code>#system</code></li><li><code>typescript</code> → 保留 → <code>#typescript</code></li></ul></li><li><strong>编程语言</strong>： <ul><li><code>python</code> → 保留 → <code>#python</code></li><li><code>json</code> → 排除（排除列表）</li></ul></li></ol><p>最终标签：<code>#plannotator #myproject #user #authentication #system #typescript #python</code>（7 个，达到上限）</p></details><h2 id="与-obsidian-集成对比" tabindex="-1">与 Obsidian 集成对比 <a class="header-anchor" href="#与-obsidian-集成对比" aria-label="Permalink to &quot;与 Obsidian 集成对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>特性</th><th>Bear 集成</th><th>Obsidian 集成</th></tr></thead><tbody><tr><td>配置复杂度</td><td>简单（仅开关）</td><td>中等（需要选择 vault 和文件夹）</td></tr><tr><td>存储</td><td>Bear 应用内</td><td>指定 vault 路径</td></tr><tr><td>文件名</td><td>Bear 自动管理</td><td><code>Title - Mon D, YYYY H-MMam.md</code></td></tr><tr><td>Frontmatter</td><td>无（Bear 不支持）</td><td>有（created, source, tags）</td></tr><tr><td>跨平台</td><td>仅 macOS</td><td>macOS/Windows/Linux</td></tr><tr><td>x-callback-url</td><td>✅ 使用</td><td>❌ 直接写文件</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">如何选择</p><ul><li>如果你只用 macOS 且喜欢 Bear：Bear 集成更简单</li><li>如果需要跨平台或自定义存储路径：Obsidian 集成更灵活</li><li>如果两者都想用：可以同时启用（批准计划会同时保存到两个地方）</li></ul></div><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><ul><li>Bear 集成通过 x-callback-url 协议工作，配置简单</li><li>只需在 Settings 中开启开关，无需指定路径</li><li>批准计划时自动保存到 Bear</li><li>标签智能生成，包含项目名、关键词、编程语言（最多 7 个）</li><li>与 Obsidian 集成相比，Bear 更简单但功能较少</li></ul><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../remote-mode/">远程/Devcontainer 模式</a></strong>。</p><p>你会学到：</p><ul><li>如何在远程环境（SSH、devcontainer、WSL）中使用 Plannotator</li><li>配置固定端口和端口转发</li><li>在远程环境中打开浏览器查看评审页面</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>Bear 配置接口</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L18-L20" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>18-20</td></tr><tr><td>保存到 Bear</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L234-L257" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>234-257</td></tr><tr><td>标签提取</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L34-L74" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>34-74</td></tr><tr><td>标题提取</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L94-L105" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>94-105</td></tr><tr><td>Bear 设置接口</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/bear.ts#L15-L17" target="_blank" rel="noreferrer"><code>packages/ui/utils/bear.ts</code></a></td><td>15-17</td></tr><tr><td>读取 Bear 设置</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/bear.ts#L22-L26" target="_blank" rel="noreferrer"><code>packages/ui/utils/bear.ts</code></a></td><td>22-26</td></tr><tr><td>保存 Bear 设置</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/bear.ts#L31-L33" target="_blank" rel="noreferrer"><code>packages/ui/utils/bear.ts</code></a></td><td>31-33</td></tr><tr><td>UI 设置组件</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/Settings.tsx#L496-L518" target="_blank" rel="noreferrer"><code>packages/ui/components/Settings.tsx</code></a></td><td>496-518</td></tr><tr><td>批准时调用 Bear</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/editor/App.tsx#L512-L514" target="_blank" rel="noreferrer"><code>packages/editor/App.tsx</code></a></td><td>512-514</td></tr><tr><td>服务器处理 Bear</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L250-L257" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>250-257</td></tr></tbody></table><p><strong>关键函数</strong>：</p><ul><li><code>saveToBear(config: BearConfig)</code>：通过 x-callback-url 将计划保存到 Bear</li><li><code>extractTags(markdown: string)</code>：从计划内容智能提取标签（最多 7 个）</li><li><code>extractTitle(markdown: string)</code>：从计划的 H1 标题提取笔记标题</li><li><code>getBearSettings()</code>：从 localStorage 读取 Bear 集成设置</li><li><code>saveBearSettings(settings)</code>：将 Bear 集成设置保存到 localStorage</li></ul><p><strong>关键常量</strong>：</p><ul><li><code>STORAGE_KEY_ENABLED = &#39;plannotator-bear-enabled&#39;</code>：localStorage 中 Bear 设置的键名</li></ul><p><strong>Bear URL 格式</strong>：</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bear</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//x-callback-url/create?title={title}&amp;text={content}&amp;open_note=no</span></span></code></pre></div></details>`,75)])])}const u=a(l,[["render",i]]);export{b as __pageData,u as default};
